from collections import defaultdict, deque

class Solution(object):
    def maxTargetNodes(self, edges1, edges2, k):
        def build_adj(edges, sz):
            adj = defaultdict(list)
            for a, b in edges:
                adj[a].append(b)
                adj[b].append(a)
            return adj

        def count_within_k(adj, start, k):
            if k < 0:
                return 0
            visited = {start}
            queue = deque([(start, 0)])
            count = 1
            while queue:
                node, dist = queue.popleft()
                if dist < k:
                    for nb in adj[node]:
                        if nb not in visited:
                            visited.add(nb)
                            count += 1
                            queue.append((nb, dist + 1))
            return count

        n = len(edges1) + 1
        m = len(edges2) + 1
        adj1 = build_adj(edges1, n)
        adj2 = build_adj(edges2, m)

        # For tree2: best count within k-1 steps from any node
        best2 = max(count_within_k(adj2, v, k - 1) for v in range(m)) if k > 0 else 0

        result = []
        for u in range(n):
            cnt1 = count_within_k(adj1, u, k)
            result.append(cnt1 + best2)
        return result
